SELECT COUNT(*) AS transaction_count
FROM `momovn-mimir.MIMIR.DLS_ALL_TRANS_V3_1`
WHERE DATE = '2024-09-26' AND SERVICE_CODE = 'Facebook ads';

column10:
SELECT COUNT(DISTINCT user_payment) AS user_count
FROM `project-5400504384186300846.BU_UTILITIES_TELCO.AIRTIME_DETAILS`
WHERE EXTRACT(MONTH FROM date) = 4 AND EXTRACT(YEAR FROM date) = 2024;

